import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Profile.css';

const Profile = () => {
  const navigate = useNavigate();
  const [userData, setUserData] = useState({
    name: '',
    email: '',
    age: '',
    sex: '',
    smoking: '',
    allergies: ''
  });
  const [originalData, setOriginalData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(false);

  useEffect(() => {
    const fetchUserData = async () => {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      try {
        // Fetch user data
        const response = await fetch(`http://localhost:5000/api/user-data/${user_id}`);
        const data = await response.json();

        if (response.ok) {
          // Fetch email from users table
          const emailResponse = await fetch(`http://localhost:5000/api/user-email/${user_id}`);
          const emailData = await emailResponse.json();

          if (emailResponse.ok) {
            const completeData = {
              ...data,
              email: emailData.email,
              smoking: data.smoking === 1 ? 'yes' : 'no', // Convert smoking value to yes/no
              sex: data.sex // Keep the sex value as is from the database
            };
            setUserData(completeData);
            setOriginalData(completeData);
          } else {
            throw new Error(emailData.error);
          }
        } else {
          throw new Error(data.error);
        }
      } catch (error) {
        console.error('Error fetching user data:', error);
        setError('Failed to load user data');
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
  }, [navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUserData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      // Update user data
      const response = await fetch(`http://localhost:5000/api/update-user-data/${user_id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          name: userData.name,
          age: userData.age,
          sex: userData.sex, // Send sex value as is to the database
          smoking: userData.smoking === 'yes' ? 1 : 0, // Convert smoking value back to 1/0
          allergy: userData.allergies
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to update user data');
      }

      // Update email if changed
      if (userData.email !== originalData.email) {
        const emailResponse = await fetch(`http://localhost:5000/api/update-email/${user_id}`, {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ email: userData.email }),
        });

        if (!emailResponse.ok) {
          throw new Error('Failed to update email');
        }
      }

      setSuccess('Changes saved successfully');
      setOriginalData(userData);
    } catch (error) {
      console.error('Error updating user data:', error);
      setError('Failed to save changes');
    }
  };

  const hasChanges = () => {
    if (!originalData) return false;
    return Object.keys(userData).some(key => userData[key] !== originalData[key]);
  };

  return (
    <div className={`profile-container ${sidebarOpen ? 'sidebar-open' : ''}`}>
      {/* Floating Menu Button */}
      <div className="floating-menu-button" onClick={() => setSidebarOpen(!sidebarOpen)}>
        <span></span>
        <span></span>
        <span></span>
      </div>

      {/* Sidebar */}
      <div className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <div className="sidebar-nav">
          <button onClick={() => navigate('/')}>Home</button>
          <button onClick={() => navigate('/recording-indicators')}>Recording Indicators</button>
          <button onClick={() => navigate('/exacerbation-forecast')}>Exacerbation Forecast</button>
          <button onClick={() => navigate('/graphs-of-changes')}>Graphs of Changes</button>
          <button onClick={() => navigate('/medication-diary')}>Medication Diary</button>
        </div>
      </div>

      <div className="profile-content">
        <h1 className="profile-heading">User Profile</h1>

        {isLoading ? (
          <div className="loading-message">Loading...</div>
        ) : (
          <>
            {error && <div className="profile-error-message">{error}</div>}
            {success && <div className="profile-success-message">{success}</div>}

            <form className="profile-form" onSubmit={handleSubmit}>
              <div className="profile-form-group">
                <input
                  type="text"
                  id="name"
                  name="name"
                  className="profile-input"
                  value={userData.name}
                  onChange={handleChange}
                  placeholder=" "
                  required
                />
                <label htmlFor="name" className="profile-label">Name</label>
              </div>

              <div className="profile-form-group">
                <input
                  type="email"
                  id="email"
                  name="email"
                  className="profile-input"
                  value={userData.email}
                  onChange={handleChange}
                  placeholder=" "
                  required
                />
                <label htmlFor="email" className="profile-label">Email</label>
              </div>

              <div className="profile-form-group">
                <input
                  type="number"
                  id="age"
                  name="age"
                  className="profile-input"
                  min="1"
                  max="120"
                  value={userData.age}
                  onChange={handleChange}
                  placeholder=" "
                  required
                />
                <label htmlFor="age" className="profile-label">Age</label>
              </div>

              <div className="profile-select-group">
                <label htmlFor="sex" className="profile-select-label">Gender</label>
                <select
                  id="sex"
                  name="sex"
                  className="profile-select"
                  value={userData.sex}
                  onChange={handleChange}
                  required
                >
                  <option value="">Select Gender</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                  <option value="other">Other</option>
                </select>
              </div>

              <div>
                <label className="profile-radio-label">Smoking Status</label>
                <div className="profile-radio-group">
                  <label className="profile-radio-option">
                    <input
                      type="radio"
                      name="smoking"
                      value="yes"
                      className="profile-radio"
                      checked={userData.smoking === 'yes'}
                      onChange={handleChange}
                    />
                    <span className="profile-radio-text">Yes</span>
                  </label>
                  <label className="profile-radio-option">
                    <input
                      type="radio"
                      name="smoking"
                      value="no"
                      className="profile-radio"
                      checked={userData.smoking === 'no'}
                      onChange={handleChange}
                    />
                    <span className="profile-radio-text">No</span>
                  </label>
                </div>
              </div>

              <div className="profile-form-group">
                <input
                  type="text"
                  id="allergies"
                  name="allergies"
                  className="profile-input"
                  value={userData.allergies}
                  onChange={handleChange}
                  placeholder=" "
                />
                <label htmlFor="allergies" className="profile-label">Allergies</label>
              </div>

              <button
                type="submit"
                className="profile-save-button"
                disabled={!hasChanges()}
              >
                Save Changes
              </button>
            </form>
          </>
        )}
      </div>
    </div>
  );
};

export default Profile;
